text:
Edgeworthova kutija i krivulja ugovora
Pareto kriterij dosad je ostao apstraktan, pa ga vrijedi vidjeti na slici koja ga čini opipljivim. Edgeworthova kutija upravo to omogućuje jer na jednom dijagramu pokazuje sve načine na koje se dva dobra mogu podijeliti između dvoje ljudi i točno ondje gdje razmjena više nikoga ne može poboljšati bez da nekoga ošteti.
Edgeworthova kutija prikazuje sve moguće raspodjele dvaju dobara između dvaju potrošača. Svaka točka u kutiji označava jednu alokaciju. Ono što dobije potrošač A mjeri se od donjeg lijevog ishodišta, a ono što dobije potrošač B iz suprotnog, gornjeg desnog ishodišta.
Alokacija je Pareto učinkovita kada više nije moguće poboljšati položaj jednog potrošača bez pogoršanja položaja drugog. Izvan ugovorne krivulje takve preraspodjele postoje i krivulje indiferencije dvaju potrošača se sijeku. Na samoj ugovornoj krivulji krivulje indiferencije su tangentne, pa su granične stope supstitucije obaju potrošača jednake i daljnja preraspodjela može poboljšati položaj jednog samo uz pogoršanje položaja drugog.
Krivulja ugovora prolazi kroz sve točke u kojima se krivulje indiferencije dvaju potrošača dodiruju. Točke A, B i C primjeri su takvih Pareto učinkovitih alokacija. Graf koji slijedi prikazuje upravo tu kutiju s krivuljom ugovora, a interaktivan je, pa klizači mijenjaju položaj točke A te naklonost svakog potrošača jednom od dvaju dobara.


Prikaži kod
viewof eb_controls = Inputs.form({
  alpha: Inputs.range([0.25, 0.75], {value: 0.6,  step: 0.05, label: "A-ova naklonost dobru X (α):"}),
  beta:  Inputs.range([0.25, 0.75], {value: 0.4,  step: 0.05, label: "B-ova naklonost dobru X (β):"}),
  pA:    Inputs.range([0.10, 0.40], {value: 0.20, step: 0.02, label: "Položaj točke A:"}),
  pB:    Inputs.range([0.35, 0.65], {value: 0.50, step: 0.02, label: "Položaj točke B:"}),
  pC:    Inputs.range([0.60, 0.90], {value: 0.80, step: 0.02, label: "Položaj točke C:"})
})









Prikaži kod
eb_alpha = eb_controls.alpha









Prikaži kod
eb_beta = eb_controls.beta









Prikaži kod
eb_pA = eb_controls.pA









Prikaži kod
eb_pB = eb_controls.pB









Prikaži kod
eb_pC = eb_controls.pC









Prikaži kod
{
  const W = 10, H = 6;
  const alpha = eb_alpha, beta = eb_beta;

  // Contract curve (Cobb-Douglas closed form)
  const CC = (x) =&gt; {
    const num = beta * H * (1 - alpha) * x;
    const den = alpha * (1 - beta) * (W - x) + beta * (1 - alpha) * x;
    return num / den;
  };

  // Sampling grid for the contract curve
  const N = 240;
  const dx = (W - 0.1) / N;
  const xsCC = d3.range(0.05, W - 0.05 + dx * 0.5, dx);
  const cc  = xsCC.map(x =&gt; ({Q: x, P: CC(x)})).filter(p =&gt; p.P &gt;= 0.02 && p.P &lt;= H - 0.02);

  // Tangent points on the contract curve
  const points = [
    {label: "A", x: eb_pA * W},
    {label: "B", x: eb_pB * W},
    {label: "C", x: eb_pC * W}
  ].map(p =&gt; ({...p, y: CC(p.x)}));

  // Short IC arc through a tangent point (x in [xp - span, xp + span])
  const arcSpan = 1.7;
  const arcSteps = 60;

  const aArcs = points.map(p =&gt; {
    const U = Math.pow(p.x, alpha) * Math.pow(p.y, 1 - alpha);
    const xLo = Math.max(0.05, p.x - arcSpan);
    const xHi = Math.min(W - 0.05, p.x + arcSpan);
    const step = (xHi - xLo) / arcSteps;
    return d3.range(xLo, xHi + step * 0.5, step)
      .map(x =&gt; ({Q: x, P: Math.pow(U / Math.pow(x, alpha), 1 / (1 - alpha)), id: p.label}))
      .filter(d =&gt; d.P &gt;= 0.05 && d.P &lt;= H - 0.05);
  });

  const bArcs = points.map(p =&gt; {
    const U = Math.pow(W - p.x, beta) * Math.pow(H - p.y, 1 - beta);
    const xLo = Math.max(0.05, p.x - arcSpan);
    const xHi = Math.min(W - 0.05, p.x + arcSpan);
    const step = (xHi - xLo) / arcSteps;
    return d3.range(xLo, xHi + step * 0.5, step)
      .map(x =&gt; ({Q: x, P: H - Math.pow(U / Math.pow(W - x, beta), 1 / (1 - beta)), id: p.label}))
      .filter(d =&gt; d.P &gt;= 0.05 && d.P &lt;= H - 0.05);
  });

  const boxOutline = [
    {Q: 0, P: 0}, {Q: W, P: 0}, {Q: W, P: H}, {Q: 0, P: H}, {Q: 0, P: 0}
  ];

  // Legend swatches (inside box, bottom-right)
  const legXa = W - 3.1, legXb = W - 2.55;
  const legY1 = 0.85, legY2 = 0.45;
  const legendBlue = [{Q: legXa, P: legY1}, {Q: legXb, P: legY1}];
  const legendRed  = [{Q: legXa, P: legY2}, {Q: legXb, P: legY2}];

  // Choose contract-curve label position near midpoint
  const labelX = Math.min(W - 1.2, points[1].x + 1.4);
  const labelY = Math.max(0.4, CC(labelX) - 0.55);

  return Plot.plot({
    width: 800,
    height: 500,
    marginLeft: 85,
    marginRight: 95,
    marginTop: 55,
    marginBottom: 60,
    style: {fontSize: "12px", fontFamily: "Public Sans, system-ui, sans-serif", color: "#3A332D"},
    x: {axis: null, domain: [-0.6, W + 0.6]},
    y: {axis: null, domain: [-0.6, H + 0.8]},
    marks: [
      // Box outline
      Plot.line(boxOutline, {x: "Q", y: "P", stroke: "#3A332D", strokeWidth: 1.5}),

      // Contract curve
      Plot.line(cc, {x: "Q", y: "P", stroke: "#1C7C54", strokeWidth: 2.5}),

      // A's IC arcs (blue) — one per tangent point, grouped by id
      ...aArcs.map(arc =&gt;
        Plot.line(arc, {x: "Q", y: "P", stroke: "#2D5A8E", strokeWidth: 2})
      ),

      // B's IC arcs (red) — one per tangent point
      ...bArcs.map(arc =&gt;
        Plot.line(arc, {x: "Q", y: "P", stroke: "#C53030", strokeWidth: 2})
      ),

      // Tangent point dots
      Plot.dot(points, {x: "x", y: "y", r: 5, fill: "#1C1916", stroke: "white", strokeWidth: 2}),

      // Point labels A, B, C
      Plot.text(points, {x: "x", y: "y", text: "label",
        fill: "#1C1916", fontSize: 13, fontWeight: 700, dx: -10, dy: -8}),

      // Contract curve label
      Plot.text([{x: labelX, y: labelY, label: "Krivulja ugovora"}],
        {x: "x", y: "y", text: "label", fill: "#1C7C54",
         fontSize: 12, fontWeight: 600, fontStyle: "italic", textAnchor: "start"}),

      // Corner labels
      Plot.text([{x: 0.2, y: -0.3, label: "Potrošač A"}],
        {x: "x", y: "y", text: "label", fill: "#2D5A8E",
         fontSize: 13, fontWeight: 700, textAnchor: "start"}),
      Plot.text([{x: W - 0.2, y: H + 0.3, label: "Potrošač B"}],
        {x: "x", y: "y", text: "label", fill: "#C53030",
         fontSize: 13, fontWeight: 700, textAnchor: "end"}),

      // Axis labels (dual perspective)
      Plot.text([{x: W / 2, y: -0.35, label: "Više dobra X za A →"}],
        {x: "x", y: "y", text: "label", fill: "#3A332D",
         fontSize: 12, textAnchor: "middle"}),
      Plot.text([{x: W / 2, y: H + 0.65, label: "← Više dobra X za B"}],
        {x: "x", y: "y", text: "label", fill: "#3A332D",
         fontSize: 12, textAnchor: "middle"}),
      Plot.text([{x: -0.4, y: H / 2, label: "↑ Više dobra Y za A"}],
        {x: "x", y: "y", text: "label", fill: "#3A332D",
         fontSize: 12, textAnchor: "middle", rotate: -90}),
      Plot.text([{x: W + 0.45, y: H / 2, label: "↓ Više dobra Y za B"}],
        {x: "x", y: "y", text: "label", fill: "#3A332D",
         fontSize: 12, textAnchor: "middle", rotate: -90}),

      // Legend swatches
      Plot.line(legendBlue, {x: "Q", y: "P", stroke: "#2D5A8E", strokeWidth: 3}),
      Plot.line(legendRed,  {x: "Q", y: "P", stroke: "#C53030", strokeWidth: 3}),
      Plot.text([{x: legXb + 0.15, y: legY1, label: "Krivulje indiferencije A"}],
        {x: "x", y: "y", text: "label", fill: "#3A332D",
         fontSize: 11, textAnchor: "start"}),
      Plot.text([{x: legXb + 0.15, y: legY2, label: "Krivulje indiferencije B"}],
        {x: "x", y: "y", text: "label", fill: "#3A332D",
         fontSize: 11, textAnchor: "start"})
    ]
  });
}









Slika 2: Točke na krivulji ugovora predstavljaju Pareto učinkovite alokacije.




Što isprobati. (1) Pomaknite klizač Položaj točke A udesno i točka A klizi po zelenoj krivulji ugovora, no plavi i crveni luk kroz nju ostaju tangentni, što potvrđuje da je svaka točka na krivulji Pareto učinkovita bez obzira na to koliko je nejednaka raspodjela dobra X. (2) Postavite A-ovu naklonost dobru X (α) i B-ovu naklonost dobru X (β) na blisku vrijednost oko 0,5 i zelena krivulja gotovo se izravna u dijagonalu kutije, jer su pri sličnim preferencijama učinkovite alokacije raspoređene ravnomjerno. (3) Razdvojite α prema 0,75 i β prema 0,25 i krivulja ugovora se snažno iskrivi prema rubu, pa Pareto učinkovite točke postaju izrazito asimetrične iako nijedna od njih nije ništa manje učinkovita od ostalih.
Kutija tako pokazuje da učinkovitost ne određuje jednu raspodjelu, nego cijeli niz njih duž krivulje ugovora, od kojih su neke vrlo nejednake. Ostaje pitanje može li tržište samo, bez vanjskog usmjeravanja, dovesti gospodarstvo do neke od tih učinkovitih točaka. Upravo na to odgovaraju dva teorema ekonomike blagostanja.

Javna dobra
Najpoznatiji primjer tržišnog neuspjeha su javna dobra. Razlog zbog kojega ih privatno tržište sustavno podbacuje leži u dvama svojstvima koja takva dobra dijele, a koja zajedno potkopavaju uobičajeni mehanizam naplate (Samuelson 1954; Musgrave 1959).

Samuelson, Paul A. 1954. „The Pure Theory of Public Expenditure“. Review of Economics and Statistics 36 (4): 387–89. https://doi.org/10.2307/1925895.

Definicija 2 Javno dobro je dobro koje je istodobno nekonkurentno (potrošnja jednog korisnika ne smanjuje dostupnost drugima) i neisključivo (teško ili skupo je spriječiti nekoga da ga koristi). Zbog te kombinacije tržište javno dobro ne može financirati jer korisnici imaju poticaj ne otkriti svoje preferencije i ostvariti ga besplatno.

Ta dva svojstva rijetko su prisutna u čistom obliku, pa je javnost nekog dobra pitanje stupnja, a ne oštre podjele. Nerivalnost znači da dodatni korisnik ne umanjuje dostupnost dobra ostalima, dok neisključivost znači da ga je teško ili preskupo uskratiti onome tko ne plati. Kada se ta dva svojstva poklope, uobičajeni mehanizam naplate po jedinici prestaje raditi jer nitko nema razloga dragovoljno otkriti koliko mu je dobro vrijedno. Najlakše je tu kombinaciju svojstava prepoznati na konkretnim primjerima, od klasičnih udžbeničkih do suvremenih.

Svjetionik je klasičan udžbenički primjer javnog dobra jer njegovo svjetlo koristi svim brodovima u blizini, a teško je naplatiti ga svakom pojedinom brodu. Suvremeniji je primjer satelitska navigacija. Europski sustav Galileo svoj otvoreni signal nudi besplatno svima, pa nijedan pojedinačni korisnik nema poticaj sam ga financirati, zbog čega je izgrađen javnim sredstvima Europske unije. U oba slučaja tržište bi takvo dobro proizvelo u premaloj količini ili ga uopće ne bi proizvelo, pa njegovo osiguravanje preuzima javni sektor. Granica između javnog i privatnog dobra pritom nije uvijek oštra jer tehnologija može promijeniti isključivost, kao kada naplatne ceste ili kriptirani satelitski signali omoguće da se prije neisključivo dobro ipak naplati. Upravo zato pitanje treba li neko dobro osigurati država nije jednom zauvijek riješeno, nego ovisi o troškovima isključivanja i o tome koliko bi tržišno rješenje smanjilo korist za društvo.1
1 Daljnje čitanje: Coase (1974), The Lighthouse in Economics; NIST/RTI (2019), Economic Benefits of GPS.
Klasični primjeri javnih dobara su nacionalna obrana, javna rasvjeta, svjetionici, zaštita od poplava, osnovna javna sigurnost, parkovi, šetnice i određeni oblici javne infrastrukture. Ako država organizira nacionalnu obranu, svi stanovnici imaju korist od sigurnosti teritorija, neovisno o tome koliko je svatko pojedinačno spreman platiti. Ako se osvijetli ulica, korist imaju svi prolaznici. Ako se izgradi nasip protiv poplave, svi stanovnici zaštićenog područja imaju korist od zaštite.
U slučaju javnih dobara pojavljuje se problem slobodnog jahača (free rider problem). Budući da se pojedinca teško može isključiti iz korištenja javnog dobra, on ima poticaj prikriti koliko mu je to dobro stvarno važno i pokušati izbjeći plaćanje. Ako zna da će ulica biti osvijetljena i bez njegova doprinosa, racionalno mu je prepustiti drugima da plate. Međutim, ako se svi ponašaju na taj način, javno dobro neće biti financirano ili će ga biti premalo. Tržište tada ne uspijeva otkriti stvarnu društvenu potražnju jer pojedinci nemaju poticaja iskreno otkriti svoje preferencije (Olson 1965).
Zato država javna dobra najčešće financira kroz poreze. Porezi omogućuju da se trošak javnog dobra raspodijeli na širu zajednicu, a ne samo na one koji bi dobrovoljno platili. To ne znači da je svaka državna potrošnja automatski opravdana. Država i dalje mora odlučiti koliko javnog dobra treba osigurati, koliko ono košta i je li društvena korist veća od društvenog troška. Kod čistih javnih dobara tržišni mehanizam naplate pojedinačne cijene jednostavno ne funkcionira dobro.
U praksi je važno razlikovati čista javna dobra od mješovitih dobara. Čista javna dobra, poput nacionalne obrane, gotovo su potpuno nekonkurentna i neisključiva. Mješovita dobra imaju neka obilježja javnih, a neka obilježja privatnih dobara. Primjerice, park je javno dostupan, ali ako postane prenapučen, potrošnja jedne osobe smanjuje kvalitetu korištenja drugima. Cesta je nekonkurentna dok nema gužve, ali u prometnoj gužvi korištenje jedne osobe smanjuje mogućnost korištenja drugima. Autocesta može biti isključiva ako se naplaćuje cestarina, ali je do određene razine prometa nekonkurentna.

Slično pitanje o granicama isključivosti danas se postavlja oko umjetne inteligencije. Kada se težinski parametri nekog jezičnog modela jednom javno objave, gotovo nikoga više nije moguće isključiti iz njihove uporabe, a to što ih jedan korisnik preuzme i pokreće ne umanjuje mogućnost da to učini bilo tko drugi, pa otvoreno objavljeni modeli poprimaju obilježja javnog dobra. Računalna snaga i golemi troškovi treniranja najsposobnijih modela, naprotiv, ostaju isključivi i skupi, slično kao naplatna cesta, pa najnaprednije sustave pružaju zatvorene komercijalne platforme. Zbog te napetosti između otvorenog koda i zatvorene infrastrukture u javnim se financijama sve više raspravlja o tome treba li temeljne sastavnice umjetne inteligencije, od računalnih kapaciteta do podataka za treniranje, tretirati kao novu klasu javnih dobara (Korinek i Lockwood 2026).

Korinek, Anton, i Lee M. Lockwood. 2026. „Public Finance in the Age of AI: A Primer“. NBER Working Paper 34873. Cambridge, MA: National Bureau of Economic Research.

Alokacijska funkcija države zato nije ograničena samo na čista javna dobra. Država često financira i dobra koja imaju šire društvene koristi, iako nisu čista javna dobra. Ceste, škole, bolnice, komunalna infrastruktura i javni prijevoz nisu uvijek javna dobra u strogom ekonomskom smislu, ali snažno utječu na funkcioniranje gospodarstva i kvalitetu života. Cesta povezuje ljude i poduzeća, smanjuje troškove prijevoza i povećava dostupnost tržišta. Obrazovanje povećava ljudski kapital. Zdravstvo povećava radnu sposobnost i smanjuje društvene troškove bolesti. Zbog tih širih koristi država može imati važnu ulogu u financiranju, organizaciji ili regulaciji takvih usluga.
Graf koji slijedi prikazuje kako se kod javnog dobra određuje društveno poželjna količina i zašto je tržište samo ne osigurava. Budući da svaka jedinica istovremeno koristi svim potrošačima (nerivalnost), agregatna potražnja dobiva se vertikalnim zbrajanjem pojedinačnih krivulja Di, pa taj zbroj predstavlja marginalnu društvenu korist ΣDi = MSB. Društveni optimum Q* nalazi se ondje gdje MSB siječe granični trošak MC. Bez prisilne koordinacije svaki pojedinac plaća samo prema vlastitoj krivulji potražnje, pa najviše što bi tržište osiguralo (QM) određuje pojedinac s najvećom spremnošću da plati, a razlika između QM i Q* posljedica je problema švercerana. Graf je interaktivan, pa klizači mijenjaju broj potrošača, njihovu heterogenost, najvišu spremnost platiti i razinu graničnog troška.


Prikaži kod
viewof pg_controls = Inputs.form({
  n: Inputs.range([2, 6],  {value: 4,  step: 1,    label: "Broj potrošača (n):"}),
  a_top: Inputs.range([30, 60], {value: 45, step: 1, label: "Najviša spremnost platiti (a₁):"}),
  delta: Inputs.range([3, 12], {value: 6,  step: 1, label: "Heterogenost potrošača (Δ):"}),
  mc:    Inputs.range([30, 90], {value: 60, step: 1, label: "Razina graničnog troška (MC):"})
})









Prikaži kod
pg_n = pg_controls.n









Prikaži kod
pg_a_top = pg_controls.a_top









Prikaži kod
pg_delta = pg_controls.delta









Prikaži kod
pg_mc = pg_controls.mc









Prikaži kod
{
  const n      = pg_n;
  const a_top  = pg_a_top;
  const delta  = pg_delta;
  const MC     = pg_mc;
  const slope  = 0.5;          // common slope b for all individual demands
  const Qmax   = 100;
  const Pmax   = 200;

  // Build individual demand intercepts: a_1 &gt; a_2 &gt; ... &gt; a_n
  const a_i = d3.range(n).map(i =&gt; a_top - i * delta);

  // Quantity grid
  const Qs = d3.range(0, Qmax + 0.5, 0.5);

  // Individual demand curves
  const indivCurves = a_i.map((a, idx) =&gt;
    Qs.map(q =&gt; ({Q: q, P: Math.max(0, a - slope * q), id: `D${idx + 1}`}))
      .filter(p =&gt; p.P &gt;= 0 && p.P &lt;= Pmax)
  );

  // Vertical aggregate: MSB(q) = Σ max(0, a_i - slope*q)
  const msb = Qs.map(q =&gt; {
    const total = a_i.reduce((acc, a) =&gt; acc + Math.max(0, a - slope * q), 0);
    return {Q: q, P: total};
  }).filter(p =&gt; p.P &gt;= 0 && p.P &lt;= Pmax);

  // MC: horizontal line at level MC
  const mcLine = [{Q: 0, P: MC}, {Q: Qmax, P: MC}];

  // Social optimum: where MSB = MC
  // Sum of individuals still in market at q: those with a_i &gt; slope*q
  // Solve numerically by scanning
  let Qstar = 0;
  for (let i = msb.length - 1; i &gt;= 0; i--) {
    if (msb[i].P &gt;= MC) { Qstar = msb[i].Q; break; }
  }

  // Market (free-rider) provision: highest individual D_1 meets MC
  // a_1 - slope*Q = MC  =&gt;  Q = (a_1 - MC)/slope, if positive
  const Qm = Math.max(0, (a_i[0] - MC) / slope);

  const P_star = MC;  // price/level along MC line

  // Color palette for individual curves (light to dark navy/teal)
  const palette = ["#A9C3DA", "#7FA3C6", "#5683B0", "#3D6B99", "#2D5A8E", "#1E3F63"];

  // Build marks dynamically
  const indivMarks = indivCurves.map((curve, idx) =&gt;
    Plot.line(curve, {x: "Q", y: "P", stroke: palette[idx % palette.length], strokeWidth: 1.5})
  );

  // Labels on individual curves at their right end
  const indivLabels = a_i.map((a, idx) =&gt; {
    const xEnd = Math.min(Qmax * 0.9, (a / slope) * 0.85);
    const yEnd = Math.max(0, a - slope * xEnd);
    return {x: xEnd, y: yEnd, label: `D${idx + 1}`, color: palette[idx % palette.length]};
  });

  return Plot.plot({
    width: 760,
    height: 520,
    marginLeft: 65,
    marginBottom: 55,
    style: {fontSize: "12px", fontFamily: "Public Sans, system-ui, sans-serif", color: "#3A332D"},
    x: {label: "Količina javnog dobra (Q) →", domain: [0, Qmax], grid: false},
    y: {label: "↑ Cijena / Korist (P)",       domain: [0, Pmax], grid: true},
    marks: [
      Plot.ruleY([0], {stroke: "#C9C3B8"}),

      // Individual demand curves
      ...indivMarks,

      // Aggregate MSB curve (thick, dark)
      Plot.line(msb, {x: "Q", y: "P", stroke: "#1C1916", strokeWidth: 3}),

      // MC line (horizontal)
      Plot.line(mcLine, {x: "Q", y: "P", stroke: "#6B1F26", strokeWidth: 2.5}),

      // Dashed guides
      Plot.ruleY([P_star], {stroke: "#6B6357", strokeDasharray: "4,3"}),
      Plot.ruleX([Qm],    {y1: 0, y2: P_star, stroke: "#6B6357", strokeDasharray: "4,3"}),
      Plot.ruleX([Qstar], {y1: 0, y2: P_star, stroke: "#6B6357", strokeDasharray: "4,3"}),

      // Equilibrium dots
      Plot.dot([{Q: Qm,    P: P_star}],
        {x: "Q", y: "P", r: 5, fill: "#6B1F26", stroke: "white", strokeWidth: 2}),
      Plot.dot([{Q: Qstar, P: P_star}],
        {x: "Q", y: "P", r: 5, fill: "#1C1916", stroke: "white", strokeWidth: 2}),

      // Curve labels (individual)
      Plot.text(indivLabels, {x: "x", y: "y", text: "label",
        fill: d =&gt; d.color, fontSize: 11, fontWeight: 600, dy: -8}),

      // MSB label
      Plot.text([{x: Qmax * 0.65, y: msb.find(p =&gt; p.Q &gt;= Qmax * 0.65)?.P ?? 0,
        label: "ΣDᵢ = MSB"}],
        {x: "x", y: "y", text: "label", fill: "#1C1916",
         fontSize: 13, fontWeight: 700, dy: -10}),

      // MC label
      Plot.text([{x: Qmax * 0.05, y: MC, label: `MC = ${MC}`}],
        {x: "x", y: "y", text: "label", fill: "#6B1F26",
         fontSize: 12, fontWeight: 600, dy: -8, textAnchor: "start"}),

      // Price label
      Plot.text([{x: 1, y: P_star, label: `P* = ${P_star.toFixed(0)}`}],
        {x: "x", y: "y", text: "label", textAnchor: "start", dy: 12,
         fontSize: 11, fill: "#3A332D"}),

      // Quantity labels
      Plot.text([{x: Qm, y: 3, label: `Q_M = ${Qm.toFixed(1)}`}],
        {x: "x", y: "y", text: "label", textAnchor: "middle",
         fontSize: 11, fill: "#6B1F26"}),
      Plot.text([{x: Qstar, y: 3, label: `Q* = ${Qstar.toFixed(1)}`}],
        {x: "x", y: "y", text: "label", textAnchor: "middle",
         fontSize: 11, fill: "#1C1916"}),

      // Headline readout: underprovision gap
      Plot.text([{x: 2, y: Pmax * 0.97,
        label: `Premala tržišna proizvodnja: Q* − Q_M = ${(Qstar - Qm).toFixed(1)}`}],
        {x: "x", y: "y", text: "label", textAnchor: "start",
         fontSize: 14, fill: "#1C1916", fontWeight: 700})
    ]
  });
}









Slika 1: Vertikalno zbrajanje individualnih krivulja potražnje za javnim dobrom i problem švercerana: tržišna razina Q_M premala je u odnosu na društveni optimum Q*.




Što isprobati. (1) Povećajte broj potrošača (n) i pratite kako se vertikalni zbroj ΣDᵢ podiže, a jaz Q* − Q_M raste jer pojedinačni doprinos ostaje sitan dok društvena korist ne. (2) Spustite razinu graničnog troška (MC) i vidjet ćete da društveni optimum Q* klizi udesno mnogo brže nego tržišna razina Q_M, što povećava podproizvodnju. (3) Sada povećajte heterogenost potrošača (Δ) uz nepromijenjenu najvišu spremnost platiti (a₁) i primijetite naizgled neočekivan ishod, naime da tržišna razina ostaje vezana uz jednog kupca s najvećom spremnošću na plaćanje, pa se s rastom raznolikosti problem švercerana zaoštrava upravo ondje gdje bi se očekivalo da brojnost pomaže.
Javna dobra time pokazuju prvi način na koji se tržišni i društveni račun razilaze, naime kada korist nekog dobra ne može biti naplaćena pojedinačnom korisniku. Postoji i zrcalni problem, kada se trošak ili korist neke odluke prelije na druge koji u njoj nisu sudjelovali. Tom se obliku neuspjeha okrećemo sljedeće.

Eksternalije
Drugi veliki oblik tržišnog neuspjeha nastaje kada cijena ne uhvati sve posljedice neke odluke. Akter koji odlučuje tada ne snosi sve troškove ni ne ubire sve koristi koje njegov izbor stvara za druge, pa se privatni i društveni račun razilaze i tržišna ravnoteža više nije Pareto učinkovita (Pigou 1920; Baumol i Oates 1988).

Baumol, William J., i Wallace E. Oates. 1988. The Theory of Environmental Policy. 2. izd. Cambridge: Cambridge University Press.

Definicija 3 Eksternalija nastaje kada odluka jednog aktera utječe na dobrobit drugih, a taj se učinak ne odražava u tržišnoj cijeni, pa se privatni i društveni trošak (ili korist) razilaze i tržišna ravnoteža nije Pareto učinkovita. Negativna eksternalija vodi prema prekomjernoj, a pozitivna prema nedovoljnoj aktivnosti.

Eksternalije mogu biti negativne i pozitivne. Negativna eksternalija nastaje kada privatna aktivnost stvara trošak za druge. Klasičan primjer je zagađenje. Tvornica koja ispušta štetne tvari u rijeku može smanjiti vlastite troškove proizvodnje jer ne plaća puni trošak onečišćenja. Međutim, taj trošak snose stanovnici nizvodno, ribari, lokalna zajednica, zdravstveni sustav ili buduće generacije. Budući da se trošak zagađenja ne nalazi u tržišnoj cijeni proizvoda, proizvodnja takvog proizvoda može biti veća nego što je društveno poželjno.
Slični primjeri negativnih eksternalija su emisije stakleničkih plinova, buka, prometne gužve, pušenje u zatvorenim prostorima, prekomjerna uporaba antibiotika ili vožnja koja povećava rizik za druge sudionike u prometu. U svim tim slučajevima privatna korist pojedinca ili poduzeća ne uključuje puni društveni trošak.
Graf koji slijedi prikazuje standardni model negativne eksternalije. Krivulja MPC (marginalni privatni trošak) odražava ono što proizvođač uzima u obzir, dok krivulja MSC (marginalni društveni trošak) uključuje i vanjske troškove koje snosi društvo. Tržišno ravnotežno presjecište MPC i potražnje (D) daje premašenu količinu QM po prenisko postavljenoj cijeni PMPC, dok je društveno optimalna razina proizvodnje Q*, koja se postiže uz cijenu P*. Osjenčani trokut između Q* i QM predstavlja gubitak blagostanja (DWL). Graf je interaktivan, pa klizači mijenjaju vanjski trošak po jedinici i elastičnost potražnje.


Prikaži kod
viewof ext_controls = Inputs.form({
  ext: Inputs.range([5, 40],  {value: 20, step: 1,    label: "Vanjski trošak po jedinici (e):"}),
  eps_d_ext: Inputs.range([0.3, 2.5], {value: 1.0, step: 0.05, label: "Elastičnost potražnje |εD|:"}),
  eps_s_ext: Inputs.range([0.3, 2.5], {value: 1.0, step: 0.05, label: "Elastičnost ponude εS:"})
})









Prikaži kod
ext_val = ext_controls.ext









Prikaži kod
eps_d_ext = ext_controls.eps_d_ext









Prikaži kod
eps_s_ext = ext_controls.eps_s_ext









Prikaži kod
{
  // Fix MPC/D equilibrium at (Qm, Pmpc) = (60, 50)
  const Qm    = 60;
  const Pmpc  = 50;
  const Qmax  = 110;
  const Pmax  = 110;
  const e     = ext_val;

  // MPC slope from elasticity: |εD| = (P/Q)*(1/b_d) =&gt; b_d = P/(Q*|εD|)
  const b_d = Pmpc / (Qm * eps_d_ext);
  // Demand: P = a_d - b_d*Q,  at (Qm, Pmpc): a_d = Pmpc + b_d*Qm
  const a_d = Pmpc + b_d * Qm;

  // MPC slope: εS = (P/Q)*(1/b_s) =&gt; b_s = P/(Q*εS)
  const b_s = Pmpc / (Qm * eps_s_ext);
  // MPC: P = c_s + b_s*Q,  at (Qm, Pmpc): c_s = Pmpc - b_s*Qm
  const c_s = Pmpc - b_s * Qm;

  // MSC = MPC + e  =&gt;  P = (c_s + e) + b_s*Q
  // Social optimum: MSC = D  =&gt;  (c_s + e) + b_s*Q* = a_d - b_d*Q*
  const Qstar = (a_d - c_s - e) / (b_d + b_s);
  const Pstar = a_d - b_d * Qstar;

  // Data arrays
  const Qs = d3.range(0, Qmax + 1);
  const demand = Qs.map(q =&gt; ({Q: q, P: a_d - b_d * q})).filter(p =&gt; p.P &gt;= 0 && p.P &lt;= Pmax);
  const mpc    = Qs.map(q =&gt; ({Q: q, P: c_s + b_s * q})).filter(p =&gt; p.P &gt;= 0 && p.P &lt;= Pmax);
  const msc    = Qs.map(q =&gt; ({Q: q, P: c_s + e + b_s * q})).filter(p =&gt; p.P &gt;= 0 && p.P &lt;= Pmax);

  // DWL triangle: vertices at (Q*, Pstar), (Qm, Pmpc), (Qm, Pstar)
  // More precisely: intersection of MSC with D at Q*, and MPC with D at Qm
  const dwlTri = [
    {Q: Qstar, P: Pstar},
    {Q: Qm,    P: Pmpc},
    {Q: Qm,    P: Pstar}
  ];

  // DWL area
  const dwl = 0.5 * Math.abs(Pstar - Pmpc) * Math.abs(Qm - Qstar);

  return Plot.plot({
    width: 760,
    height: 500,
    marginLeft: 65,
    marginBottom: 55,
    style: {fontSize: "12px", fontFamily: "Public Sans, system-ui, sans-serif", color: "#3A332D"},
    x: {label: "Količina (Q) →", domain: [0, Qmax], grid: false},
    y: {label: "↑ Cijena / Trošak (P)", domain: [0, Pmax], grid: true},
    marks: [
      Plot.ruleY([0], {stroke: "#C9C3B8"}),

      // DWL triangle (shaded)
      Plot.line([...dwlTri, dwlTri[0]],
        {x: "Q", y: "P", stroke: "#6B1F26", strokeWidth: 1,
         fill: "#D8B5B3", fillOpacity: 0.65, curve: "linear"}),

      // Curves
      Plot.line(demand, {x: "Q", y: "P", stroke: "#2D5A8E", strokeWidth: 2.5}),
      Plot.line(mpc,    {x: "Q", y: "P", stroke: "#4A6B5C", strokeWidth: 2}),
      Plot.line(msc,    {x: "Q", y: "P", stroke: "#6B1F26", strokeWidth: 2}),

      // Dashed guides
      Plot.ruleY([Pstar], {stroke: "#6B6357", strokeDasharray: "4,3"}),
      Plot.ruleY([Pmpc],  {stroke: "#6B6357", strokeDasharray: "4,3"}),
      Plot.ruleX([Qstar], {y1: 0, y2: Pstar, stroke: "#6B6357", strokeDasharray: "4,3"}),
      Plot.ruleX([Qm],    {y1: 0, y2: Pmpc,  stroke: "#6B6357", strokeDasharray: "4,3"}),

      // Equilibrium dots
      Plot.dot([{Q: Qm,    P: Pmpc}],
        {x: "Q", y: "P", r: 5, fill: "#4A6B5C", stroke: "white", strokeWidth: 2}),
      Plot.dot([{Q: Qstar, P: Pstar}],
        {x: "Q", y: "P", r: 5, fill: "#6B1F26", stroke: "white", strokeWidth: 2}),

      // Curve labels
      Plot.text([{x: Qmax * 0.82, y: a_d - b_d * Qmax * 0.82, label: `D (|εD|=${eps_d_ext.toFixed(2)})`}],
        {x: "x", y: "y", text: "label", fill: "#2D5A8E", fontSize: 12, fontWeight: 600, dy: -8}),
      Plot.text([{x: Qmax * 0.82, y: c_s + b_s * Qmax * 0.82, label: `MPC (εS=${eps_s_ext.toFixed(2)})`}],
        {x: "x", y: "y", text: "label", fill: "#4A6B5C", fontSize: 12, fontWeight: 600, dy: -8}),
      Plot.text([{x: Qmax * 0.7, y: c_s + e + b_s * Qmax * 0.7, label: `MSC (e=${e})`}],
        {x: "x", y: "y", text: "label", fill: "#6B1F26", fontSize: 12, fontWeight: 600, dy: -8}),

      // Price & quantity labels on axes
      Plot.text([{x: 1, y: Pstar, label: `P* = ${Pstar.toFixed(1)}`}],
        {x: "x", y: "y", text: "label", textAnchor: "start", dy: -7, fontSize: 11, fill: "#6B1F26"}),
      Plot.text([{x: 1, y: Pmpc, label: `P_MPC = ${Pmpc.toFixed(1)}`}],
        {x: "x", y: "y", text: "label", textAnchor: "start", dy: 12, fontSize: 11, fill: "#4A6B5C"}),
      Plot.text([{x: Qstar, y: 2, label: `Q* = ${Qstar.toFixed(1)}`}],
        {x: "x", y: "y", text: "label", textAnchor: "middle", dy: 0, fontSize: 11, fill: "#6B1F26"}),
      Plot.text([{x: Qm, y: 2, label: `Q_M = ${Qm.toFixed(1)}`}],
        {x: "x", y: "y", text: "label", textAnchor: "middle", dy: 0, fontSize: 11, fill: "#4A6B5C"}),

      // DWL readout
      Plot.text([{x: 2, y: Pmax * 0.97,
        label: `Gubitak blagostanja (DWL) = ${dwl.toFixed(1)}`}],
        {x: "x", y: "y", text: "label", textAnchor: "start",
         fontSize: 14, fill: "#6B1F26", fontWeight: 700})
    ]
  });
}









Slika 2: Negativna eksternalija i gubitak blagostanja: tržišna ravnoteža (Q_M, P_MPC) premašuje društveni optimum (Q, P) jer MPC ne uključuje vanjski trošak.




Što isprobati. (1) Povećajte vanjski trošak po jedinici (e) i pratite kako se MSC odmiče od MPC, društveni optimum Q* pomiče ulijevo, a osjenčani trokut gubitka blagostanja raste. (2) Vratite (e) na nisku vrijednost i vidjet ćete kako se MSC gotovo poklopi s MPC, pa gubitak blagostanja iščezava jer privatni i društveni trošak postaju jedva razlučivi. (3) Uz fiksni (e) smanjite elastičnost potražnje |εD| prema 0,3 i primijetite protuintuitivan ishod, naime da kruta potražnja zadržava količinu blizu Q_M unatoč eksternaliji, pa porez koji bi je trebao obuzdati pomiče količinu vrlo malo, a glavnina tereta pada na cijenu.
Negativna eksternalija pokazuje slučaj u kojem tržište proizvodi previše nečega štetnog. Jednako je čest i obrnut slučaj, kada aktivnost stvara korist za druge pa je tržište proizvodi premalo. Taj zrcalni problem i instrumente kojima ga država ispravlja razmatramo u nastavku.

Pozitivne eksternalije i instrumenti ispravljanja
Pozitivna eksternalija nastaje kada aktivnost pojedinca ili poduzeća stvara korist za druge, a ta korist nije u potpunosti plaćena. Primjer je cijepljenje. Osoba koja se cijepi štiti sebe, ali istodobno smanjuje vjerojatnost širenja bolesti na druge. Slično vrijedi za obrazovanje. Obrazovaniji pojedinac ima veću osobnu korist kroz veće mogućnosti zapošljavanja i dohotka, ali društvo također ima koristi kroz veću produktivnost, informiranije građane, manju sklonost kriminalu i bolju sposobnost prilagodbe tehnološkim promjenama. Istraživanje i razvoj također stvaraju pozitivne eksternalije jer se nova znanja mogu prelijevati na druga poduzeća, sektore i buduće inovacije.
Kod negativnih eksternalija tržište obično proizvodi previše aktivnosti koja stvara štetu. Kod pozitivnih eksternalija tržište obično proizvodi premalo aktivnosti koja stvara korist. Zadaća države je približiti privatne poticaje društvenim troškovima i koristima.
Graf koji slijedi prikazuje zrcalnu sliku prethodnog, slučaj u kojem društvene koristi premašuju privatne. Krivulja MPB (marginalna privatna korist) odražava potražnju koju potrošači sami iskazuju, dok krivulja MSB (marginalna društvena korist) uključuje i vanjske koristi, primjerice veću produktivnost cijelog gospodarstva od obrazovanijih pojedinaca. Tržišno presjecište MPB i ponude (S) daje nedovoljnu količinu QM po cijeni PM, dok je društveno optimalna razina Q* uz cijenu P*. Osjenčani trokut prikazuje propuštenu društvenu korist, odnosno gubitak blagostanja zbog premale proizvodnje. Graf je interaktivan, pa klizači mijenjaju vanjsku korist po jedinici i elastičnost ponude.


Prikaži kod
viewof pos_controls = Inputs.form({
  extb: Inputs.range([5, 40],  {value: 20, step: 1,    label: "Vanjska korist po jedinici (b):"}),
  eps_d_pos: Inputs.range([0.3, 2.5], {value: 1.0, step: 0.05, label: "Elastičnost potražnje |εD|:"}),
  eps_s_pos: Inputs.range([0.3, 2.5], {value: 1.0, step: 0.05, label: "Elastičnost ponude εS:"})
})









Prikaži kod
extb_val = pos_controls.extb









Prikaži kod
eps_d_pos = pos_controls.eps_d_pos









Prikaži kod
eps_s_pos = pos_controls.eps_s_pos









Prikaži kod
{
  // Fix MPB/S market equilibrium at (Qm, Pm) = (50, 50)
  const Qm   = 50;
  const Pm   = 50;
  const Qmax = 110;
  const Pmax = 110;
  const b    = extb_val;

  // MPB slope from elasticity: b_d = P/(Q*|εD|)
  const b_d = Pm / (Qm * eps_d_pos);
  // MPB: P = a_d - b_d*Q,  at (Qm, Pm): a_d = Pm + b_d*Qm
  const a_d = Pm + b_d * Qm;

  // Supply slope: b_s = P/(Q*εS)
  const b_s = Pm / (Qm * eps_s_pos);
  // S: P = c_s + b_s*Q,  at (Qm, Pm): c_s = Pm - b_s*Qm
  const c_s = Pm - b_s * Qm;

  // MSB = MPB + b  =&gt;  P = (a_d + b) - b_d*Q
  // Social optimum: MSB = S  =&gt;  (a_d + b) - b_d*Q* = c_s + b_s*Q*
  const Qstar = (a_d + b - c_s) / (b_d + b_s);
  const Pstar = c_s + b_s * Qstar;

  // MSB at Q_M (top-left vertex of DWL triangle)
  const MSB_Qm = a_d + b - b_d * Qm;

  const Qs = d3.range(0, Qmax + 1);
  const mpb    = Qs.map(q =&gt; ({Q: q, P: a_d - b_d * q})).filter(p =&gt; p.P &gt;= 0 && p.P &lt;= Pmax);
  const msb    = Qs.map(q =&gt; ({Q: q, P: a_d + b - b_d * q})).filter(p =&gt; p.P &gt;= 0 && p.P &lt;= Pmax);
  const supply = Qs.map(q =&gt; ({Q: q, P: c_s + b_s * q})).filter(p =&gt; p.P &gt;= 0 && p.P &lt;= Pmax);

  // DWL triangle: area between MSB (top) and S (bottom), from Q_M to Q*
  // Vertices: (Q_M, P_M) on S, (Q_M, MSB(Q_M)) on MSB, (Q*, P*) intersection
  const dwlTri = [
    {Q: Qm,    P: Pm},
    {Q: Qm,    P: MSB_Qm},
    {Q: Qstar, P: Pstar}
  ];

  // DWL area = 0.5 * (MSB(Q_M) - P_M) * (Q* - Q_M)
  const dwl = 0.5 * Math.abs(MSB_Qm - Pm) * Math.abs(Qstar - Qm);

  return Plot.plot({
    width: 760,
    height: 500,
    marginLeft: 65,
    marginBottom: 55,
    style: {fontSize: "12px", fontFamily: "Public Sans, system-ui, sans-serif", color: "#3A332D"},
    x: {label: "Količina (Q) →", domain: [0, Qmax], grid: false},
    y: {label: "↑ Cijena / Korist (P)", domain: [0, Pmax], grid: true},
    marks: [
      Plot.ruleY([0], {stroke: "#C9C3B8"}),

      // DWL triangle (shaded — propuštena korist)
      Plot.line([...dwlTri, dwlTri[0]],
        {x: "Q", y: "P", stroke: "#C8985E", strokeWidth: 1,
         fill: "#E8D6B8", fillOpacity: 0.65, curve: "linear"}),

      // Curves
      Plot.line(mpb,    {x: "Q", y: "P", stroke: "#2D5A8E", strokeWidth: 2.5}),
      Plot.line(msb,    {x: "Q", y: "P", stroke: "#2B6CB0", strokeWidth: 2}),
      Plot.line(supply, {x: "Q", y: "P", stroke: "#4A6B5C", strokeWidth: 2}),

      // Dashed guides
      Plot.ruleY([Pstar], {stroke: "#6B6357", strokeDasharray: "4,3"}),
      Plot.ruleY([Pm],    {stroke: "#6B6357", strokeDasharray: "4,3"}),
      Plot.ruleX([Qstar], {y1: 0, y2: Pstar, stroke: "#6B6357", strokeDasharray: "4,3"}),
      Plot.ruleX([Qm],    {y1: 0, y2: MSB_Qm, stroke: "#6B6357", strokeDasharray: "4,3"}),

      // Equilibrium dots
      Plot.dot([{Q: Qm,    P: Pm}],
        {x: "Q", y: "P", r: 5, fill: "#2D5A8E", stroke: "white", strokeWidth: 2}),
      Plot.dot([{Q: Qstar, P: Pstar}],
        {x: "Q", y: "P", r: 5, fill: "#2B6CB0", stroke: "white", strokeWidth: 2}),

      // Curve labels
      Plot.text([{x: Qmax * 0.82, y: a_d - b_d * Qmax * 0.82, label: `D = MPB (|εD|=${eps_d_pos.toFixed(2)})`}],
        {x: "x", y: "y", text: "label", fill: "#2D5A8E", fontSize: 12, fontWeight: 600, dy: -8}),
      Plot.text([{x: Qmax * 0.7, y: a_d + b - b_d * Qmax * 0.7, label: `MSB (b=${b})`}],
        {x: "x", y: "y", text: "label", fill: "#2B6CB0", fontSize: 12, fontWeight: 600, dy: -8}),
      Plot.text([{x: Qmax * 0.82, y: c_s + b_s * Qmax * 0.82, label: `S (εS=${eps_s_pos.toFixed(2)})`}],
        {x: "x", y: "y", text: "label", fill: "#4A6B5C", fontSize: 12, fontWeight: 600, dy: -8}),

      // Price & quantity labels on axes
      Plot.text([{x: 1, y: Pstar, label: `P* = ${Pstar.toFixed(1)}`}],
        {x: "x", y: "y", text: "label", textAnchor: "start", dy: -7, fontSize: 11, fill: "#2B6CB0"}),
      Plot.text([{x: 1, y: Pm, label: `P_M = ${Pm.toFixed(1)}`}],
        {x: "x", y: "y", text: "label", textAnchor: "start", dy: 12, fontSize: 11, fill: "#2D5A8E"}),
      Plot.text([{x: Qm, y: 2, label: `Q_M = ${Qm.toFixed(1)}`}],
        {x: "x", y: "y", text: "label", textAnchor: "middle", dy: 0, fontSize: 11, fill: "#2D5A8E"}),
      Plot.text([{x: Qstar, y: 2, label: `Q* = ${Qstar.toFixed(1)}`}],
        {x: "x", y: "y", text: "label", textAnchor: "middle", dy: 0, fontSize: 11, fill: "#2B6CB0"}),

      // DWL readout
      Plot.text([{x: 2, y: Pmax * 0.97,
        label: `Propuštena korist (DWL) = ${dwl.toFixed(1)}`}],
        {x: "x", y: "y", text: "label", textAnchor: "start",
         fontSize: 14, fill: "#9A6F38", fontWeight: 700})
    ]
  });
}









Slika 3: Pozitivna eksternalija i propuštena korist: tržišna razina Q_M preniska je u odnosu na društveni optimum Q* jer MPB ne uključuje vanjsku korist.




Što isprobati. (1) Povećajte vanjsku korist po jedinici (b) i pratite kako se MSB podiže iznad MPB, društveni optimum Q* pomiče udesno, a osjenčani trokut propuštene koristi raste jer tržište proizvodi premalo. (2) Spustite (b) prema nuli i vidjet ćete kako se MSB stopi s MPB, pa propuštena korist nestaje i tržišna razina Q_M postaje društveno optimalna. (3) Uz izdašnu vanjsku korist smanjite elastičnost ponude εS prema 0,3 i primijetite protuintuitivan ishod, naime da kruta ponuda zadržava količinu blizu Q_M unatoč velikoj vanjskoj koristi, pa subvencija koja bi je trebala potaknuti diže uglavnom cijenu, a količinu pomiče tek skromno.
Najpoznatiji instrument za ispravljanje negativnih eksternalija je Pigouov porez. Ako aktivnost stvara društveni trošak koji nije uključen u cijenu, država može uvesti porez koji povećava privatni trošak te aktivnosti. Time se poduzeća i potrošači potiču da smanje štetno ponašanje. Primjeri su porezi na emisije ugljika, trošarine na gorivo, porezi na duhan ili porezi na alkohol. Logika je jednostavna jer ako neka aktivnost stvara društveni trošak, njezina cijena treba taj trošak odražavati.
Koliko bi točno takav porez trebao iznositi pitanje je koje vodi do empirijske veličine vanjskog troška. Za klimatske emisije ta se veličina naziva društvenim troškom ugljika (social cost of carbon) i predstavlja procijenjenu štetu koju nanosi svaka dodatna tona ugljičnog dioksida, a upravo bi joj Pigouov porez na emisije trebao biti jednak. Procjene se, međutim, kreću u širokom rasponu i s vremenom rastu kako modeli uključuju sve više dugoročnih i teško mjerljivih šteta, od desetak do više stotina dolara po toni (Nordhaus 2017; Rennert i ostali 2022). Sam taj raspon pokazuje da visina ispravnog poreza nije tehnička činjenica nego procjena opterećena pretpostavkama o diskontiranju i budućim štetama, što objašnjava zašto je i kod načelno prihvaćenog instrumenta njegova kalibracija predmet trajnog spora.

Nordhaus, William D. 2017. „Revisiting the Social Cost of Carbon“. Proceedings of the National Academy of Sciences 114 (7): 1518–23. https://doi.org/10.1073/pnas.1609244114.

Rennert, Kevin i ostali. 2022. „Comprehensive Evidence Implies a Higher Social Cost of CO2“. Nature 610: 687–92. https://doi.org/10.1038/s41586-022-05224-9.
Kod pozitivnih eksternalija država može koristiti subvencije, javno financiranje ili porezne olakšice. Ako obrazovanje, cijepljenje ili istraživanje i razvoj stvaraju društvene koristi veće od privatnih koristi pojedinca, država ih može poticati kako bi se povećala njihova razina. Zato države financiraju škole i sveučilišta, subvencioniraju istraživanje, organiziraju javnozdravstvene kampanje ili financiraju preventivne programe.
Država eksternalije može rješavati i regulacijom. Može propisati maksimalne emisije, tehničke standarde, obveznu uporabu sigurnosne opreme, zabranu odlaganja otpada u rijeke ili standarde energetske učinkovitosti. Može koristiti i tržišne instrumente poput trgovanja emisijskim dozvolama.

Asimetrične informacije
Treći oblik tržišnog neuspjeha su asimetrične informacije. Tržišta funkcioniraju najbolje kada kupci i prodavatelji, poslodavci i radnici, banke i dužnici ili osiguravatelji i osiguranici raspolažu relevantnim informacijama. U stvarnosti to često nije slučaj. Jedna strana u razmjeni može znati mnogo više od druge, a ta informacijska neravnoteža može dovesti do neučinkovitih ili nepravednih ishoda, bilo prije sklapanja ugovora bilo nakon njega.

Definicija 4 Asimetrične informacije nastaju kada jedna strana u razmjeni raspolaže relevantnim znanjem koje druga strana nema, što može dovesti do nepovoljnog izbora (adverse selection, pred sklapanjem ugovora) ili moralnog hazarda (moral hazard, nakon sklapanja ugovora). Oba mehanizma smanjuju učinkovitost tržišnog ishoda.

Najpoznatiji primjer dao je George Akerlof u radu o tržištu „limuna”, odnosno rabljenih automobila loše kvalitete (Akerlof 1970). Prodavatelj rabljenog automobila zna više o stvarnom stanju automobila od kupca. Kupac ne može lako razlikovati kvalitetan automobil od lošeg, pa je spreman platiti samo prosječnu cijenu. Ta prosječna cijena može biti preniska za vlasnike kvalitetnih automobila, koji se zato povlače s tržišta. Na tržištu ostaju uglavnom lošiji automobili. Rezultat je pad kvalitete i smanjenje razmjene, iako bi u uvjetima potpunih informacija tržište moglo bolje funkcionirati.

Akerlof, George A. 1970. „The Market for ‚Lemons‘: Quality Uncertainty and the Market Mechanism“. Quarterly Journal of Economics 84 (3): 488–500. https://doi.org/10.2307/1879431.
Asimetrične informacije stvaraju dva važna problema, nepovoljan izbor i moralni hazard. Nepovoljan izbor nastaje prije sklapanja ugovora. To je situacija u kojoj se zbog informacijske neravnoteže na tržištu zadržavaju lošiji rizici ili lošija kvaliteta. Primjer je tržište zdravstvenog osiguranja. Osobe koje znaju da imaju veći zdravstveni rizik sklonije su kupiti osiguranje, dok se zdraviji pojedinci mogu povući ako je premija previsoka. Ako osiguravatelj ne može dobro razlikovati rizične i manje rizične pojedince, premije rastu, a tržište može postati nestabilno.
Graf koji slijedi prikazuje kako nepovoljan izbor postupno istiskuje kvalitetnu robu s tržišta. Kada kupci ne razlikuju kvalitetu, spremni su platiti samo prosječnu cijenu, a ta je cijena preniska za prodavače kvalitetne robe (krivulja Svisoka), pa oni napuštaju tržište. Ostaje samo loša roba (krivulja Sloša), a ravnoteža se pomiče s točke (Q₁, Pvisoka) na (Q₂, Pniska), pri čemu se u graničnim slučajevima tržište može potpuno urušiti. Graf je interaktivan, pa klizači mijenjaju premiju za kvalitetu i elastičnost potražnje.


Prikaži kod
viewof asi_controls = Inputs.form({
  qprem: Inputs.range([5, 40],  {value: 20, step: 1,    label: "Premija za kvalitetu (Δ):"}),
  eps_d_asi: Inputs.range([0.3, 2.5], {value: 1.0, step: 0.05, label: "Elastičnost potražnje |εD|:"}),
  eps_s_asi: Inputs.range([0.3, 2.5], {value: 1.0, step: 0.05, label: "Elastičnost ponude εS:"})
})









Prikaži kod
qprem_val = asi_controls.qprem









Prikaži kod
eps_d_asi = asi_controls.eps_d_asi









Prikaži kod
eps_s_asi = asi_controls.eps_s_asi









Prikaži kod
{
  // Anchor low-quality equilibrium at (Q2, P_niska) = (60, 50)
  const Q2     = 60;
  const P_low  = 50;
  const Qmax   = 110;
  const Pmax   = 120;
  const dQ     = qprem_val;

  // Demand slope from elasticity at low-quality eq
  const b_d = P_low / (Q2 * eps_d_asi);
  const a_d = P_low + b_d * Q2;            // D: P = a_d - b_d*Q

  // Supply slope from elasticity at low-quality eq
  const b_s = P_low / (Q2 * eps_s_asi);
  const c_s = P_low - b_s * Q2;            // S_low: P = c_s + b_s*Q
  // S_high shifted up by Δ: P = (c_s + Δ) + b_s*Q

  // High-quality equilibrium: D = S_high
  // a_d - b_d*Q = (c_s + Δ) + b_s*Q
  const Q1     = (a_d - c_s - dQ) / (b_d + b_s);
  const P_high = a_d - b_d * Q1;

  const Qs = d3.range(0, Qmax + 1);
  const demand = Qs.map(q =&gt; ({Q: q, P: a_d - b_d * q})).filter(p =&gt; p.P &gt;= 0 && p.P &lt;= Pmax);
  const sLow   = Qs.map(q =&gt; ({Q: q, P: c_s + b_s * q})).filter(p =&gt; p.P &gt;= 0 && p.P &lt;= Pmax);
  const sHigh  = Qs.map(q =&gt; ({Q: q, P: c_s + dQ + b_s * q})).filter(p =&gt; p.P &gt;= 0 && p.P &lt;= Pmax);

  // Quantity reduction & price drop
  const qDrop  = Q2 - Q1;
  const pDrop  = P_high - P_low;

  // Detect potential market collapse: high-quality eq quantity ≤ 0
  const collapse = Q1 &lt;= 0;

  return Plot.plot({
    width: 760,
    height: 500,
    marginLeft: 65,
    marginBottom: 55,
    style: {fontSize: "12px", fontFamily: "Public Sans, system-ui, sans-serif", color: "#3A332D"},
    x: {label: "Količina (Q) →", domain: [0, Qmax], grid: false},
    y: {label: "↑ Cijena (P)",    domain: [0, Pmax], grid: true},
    marks: [
      Plot.ruleY([0], {stroke: "#C9C3B8"}),

      // Curves
      Plot.line(demand, {x: "Q", y: "P", stroke: "#2D5A8E", strokeWidth: 2.5}),
      Plot.line(sLow,   {x: "Q", y: "P", stroke: "#4A6B5C", strokeWidth: 2}),
      Plot.line(sHigh,  {x: "Q", y: "P", stroke: "#4A6B5C", strokeWidth: 2, strokeDasharray: "6,4"}),

      // Shift arrow from S_high to S_low at a representative Q (Q2 * 0.6)
      Plot.link(
        [{x1: Q2 * 0.55, y1: c_s + dQ + b_s * Q2 * 0.55,
          x2: Q2 * 0.55, y2: c_s + b_s * Q2 * 0.55}],
        {x1: "x1", y1: "y1", x2: "x2", y2: "y2",
         stroke: "#6B1F26", strokeWidth: 2, markerEnd: "arrow"}),

      // Dashed price/quantity guides
      Plot.ruleY([P_high], {stroke: "#6B6357", strokeDasharray: "4,3"}),
      Plot.ruleY([P_low],  {stroke: "#6B6357", strokeDasharray: "4,3"}),
      Plot.ruleX([Q1],     {y1: 0, y2: P_high, stroke: "#6B6357", strokeDasharray: "4,3"}),
      Plot.ruleX([Q2],     {y1: 0, y2: P_low,  stroke: "#6B6357", strokeDasharray: "4,3"}),

      // Equilibrium dots
      Plot.dot([{Q: Q1, P: P_high}],
        {x: "Q", y: "P", r: 5, fill: "#1C1916", stroke: "white", strokeWidth: 2}),
      Plot.dot([{Q: Q2, P: P_low}],
        {x: "Q", y: "P", r: 5, fill: "#6B1F26", stroke: "white", strokeWidth: 2}),

      // Curve labels
      Plot.text([{x: Qmax * 0.82, y: a_d - b_d * Qmax * 0.82, label: `D (|εD|=${eps_d_asi.toFixed(2)})`}],
        {x: "x", y: "y", text: "label", fill: "#2D5A8E", fontSize: 12, fontWeight: 600, dy: -8}),
      Plot.text([{x: Qmax * 0.82, y: c_s + b_s * Qmax * 0.82, label: `S_loša (εS=${eps_s_asi.toFixed(2)})`}],
        {x: "x", y: "y", text: "label", fill: "#4A6B5C", fontSize: 12, fontWeight: 600, dy: -8}),
      Plot.text([{x: Qmax * 0.7, y: c_s + dQ + b_s * Qmax * 0.7, label: `S_visoka (Δ=${dQ})`}],
        {x: "x", y: "y", text: "label", fill: "#4A6B5C", fontSize: 12, fontWeight: 600, dy: -8}),

      // Price labels
      Plot.text([{x: 1, y: P_high, label: `P_visoka = ${P_high.toFixed(1)}`}],
        {x: "x", y: "y", text: "label", textAnchor: "start", dy: -7, fontSize: 11, fill: "#1C1916"}),
      Plot.text([{x: 1, y: P_low, label: `P_niska = ${P_low.toFixed(1)}`}],
        {x: "x", y: "y", text: "label", textAnchor: "start", dy: 12, fontSize: 11, fill: "#6B1F26"}),

      // Quantity labels
      Plot.text([{x: Q1, y: 2, label: `Q₁ = ${Q1.toFixed(1)}`}],
        {x: "x", y: "y", text: "label", textAnchor: "middle", fontSize: 11, fill: "#1C1916"}),
      Plot.text([{x: Q2, y: 2, label: `Q₂ = ${Q2.toFixed(1)}`}],
        {x: "x", y: "y", text: "label", textAnchor: "middle", fontSize: 11, fill: "#6B1F26"}),

      // Top readouts
      Plot.text([{x: 2, y: Pmax * 0.97,
        label: collapse ? "⚠ Tržište se urušava (Q₁ ≤ 0)" : `Pad količine: ΔQ = ${qDrop.toFixed(1)}`}],
        {x: "x", y: "y", text: "label", textAnchor: "start",
         fontSize: 14, fill: "#6B1F26", fontWeight: 700}),
      Plot.text([{x: 2, y: Pmax * 0.91,
        label: `Pad cijene: ΔP = ${pDrop.toFixed(1)}`}],
        {x: "x", y: "y", text: "label", textAnchor: "start",
         fontSize: 13, fill: "#1C1916", fontWeight: 600})
    ]
  });
}









Slika 4: Tržište limuna i nepovoljan izbor: informacijska asimetrija tjera kvalitetne prodavače s tržišta, pa ravnoteža pada s (Q₁, P_visoka) na (Q₂, P_niska).




Što isprobati. (1) Povećavajte premiju za kvalitetu (Δ) i pratite kako se S_visoka sve više odiže od S_loša, pa ravnoteža kvalitetne robe (Q₁, P_visoka) klizi ulijevo i prema gore, a pad količine ΔQ raste. (2) Gurnite (Δ) dovoljno visoko i vidjet ćete kako Q₁ pada na nulu, pa se pojavljuje upozorenje da se tržište kvalitetne robe potpuno urušava, baš kao u Akerlofovu primjeru limuna. (3) Sada uz visoku premiju smanjite elastičnost potražnje |εD| prema 0,3 i primijetite protuintuitivan ishod, naime da kruta potražnja prigušuje pad količine, ali zato cijenu kvalitetne robe gura znatno više, pa se asimetrija očituje skokom cijene umjesto nestankom količine.
Nepovoljan izbor pokazuje kako informacijska neravnoteža djeluje već prije sklapanja ugovora, kroz odabir onih koji u razmjenu ulaze. Drugi se njezin oblik javlja tek nakon što je ugovor sklopljen, kada zaštita koju on pruža počne mijenjati ponašanje strane koja je njome pokrivena.

Moralni hazard i informacijske mjere države
Moralni hazard nastaje nakon sklapanja ugovora. To je situacija u kojoj osiguranje ili zaštita mijenja ponašanje pojedinca jer on više ne snosi puni trošak svojih odluka. Osoba koja ima potpuno osiguranje može biti manje oprezna. Banka koja očekuje da će je država spasiti u krizi može preuzimati veće rizike. Poduzeće koje očekuje stalne državne potpore može manje ulagati u učinkovitost i prilagodbu. Klasična rješenja uključuju dijeljenje rizika kroz franšizu, suosiguranje i nadzor.
Graf koji slijedi prikazuje kako osiguranje mijenja razinu rizika koju akter dragovoljno preuzima. Agent bira razinu rizičnog ponašanja e uspoređujući privatnu korist, primjerice brzinu, prinos ili udobnost, s troškom mogućih šteta. Bez osiguranja snosi puni trošak C(e) i bira nisku razinu rizika e*, a s osiguranjem osiguratelj pokriva dio (θ) štete, pa agent percipira samo (1−θ)·C(e), krivulja postaje plića i bira višu razinu rizika eM &gt; e*. Razlika je posljedica moralnog hazarda. Graf je interaktivan, pa klizači mijenjaju pokriće osiguranja i konveksnost troška.


Prikaži kod
viewof mh_controls = Inputs.form({
  theta: Inputs.range([0, 0.9],  {value: 0.5, step: 0.05, label: "Pokriće osiguranja (θ):"}),
  k:     Inputs.range([0.05, 0.5], {value: 0.15, step: 0.01, label: "Konveksnost troška (k):"}),
  m:     Inputs.range([0.5, 3.0], {value: 1.5, step: 0.05, label: "Marginalna korist od rizika (m):"})
})









Prikaži kod
mh_theta = mh_controls.theta









Prikaži kod
mh_k = mh_controls.k









Prikaži kod
mh_m = mh_controls.m









Prikaži kod
{
  const theta = mh_theta;
  const k     = mh_k;
  const m     = mh_m;
  const emax  = 12;
  const Cmax  = 18;

  // Cost function: C(e) = 1 + k*e^2  (convex)
  // Without insurance, agent sees full C(e)
  // With insurance, agent perceives (1 - theta) * variable cost: 1 + k*(1 - theta)*e^2
  // Agent's chosen e: MB = m, MC_perceived = 2*k_eff*e  =&gt;  e = m / (2*k_eff)
  const eStar = m / (2 * k);
  const eM    = m / (2 * k * (1 - theta));

  const eMshown = Math.min(eM, emax * 0.98);

  const es = d3.range(0, emax + 0.05, 0.05);
  const cFull = es.map(e =&gt; ({e: e, C: 1 + k * e * e}))
                  .filter(p =&gt; p.C &lt;= Cmax);
  const cIns  = es.map(e =&gt; ({e: e, C: 1 + k * (1 - theta) * e * e}))
                  .filter(p =&gt; p.C &lt;= Cmax);

  // Costs at the two chosen e levels (real, social cost — on the full curve)
  const C_at_eStar = 1 + k * eStar * eStar;
  const C_at_eM    = 1 + k * Math.min(eM, emax) * Math.min(eM, emax);

  // Excess social cost from moral hazard (vs net benefit gained):
  // Cost increase: C(eM) - C(e*); Benefit increase: m*(eM - e*)
  const dwl = Math.max(0, (C_at_eM - C_at_eStar) - m * (eM - eStar));

  return Plot.plot({
    width: 760,
    height: 500,
    marginLeft: 70,
    marginBottom: 55,
    style: {fontSize: "12px", fontFamily: "Public Sans, system-ui, sans-serif", color: "#3A332D"},
    x: {label: "Rizično ponašanje (e) →", domain: [0, emax], grid: false},
    y: {label: "↑ Trošak / šteta",        domain: [0, Cmax], grid: true},
    marks: [
      Plot.ruleY([0], {stroke: "#C9C3B8"}),

      // Cost curves
      Plot.line(cFull, {x: "e", y: "C", stroke: "#6B1F26", strokeWidth: 2.5, strokeDasharray: "6,4"}),
      Plot.line(cIns,  {x: "e", y: "C", stroke: "#1C1916", strokeWidth: 2.5}),

      // Dashed verticals at e* and eM
      Plot.ruleX([eStar],   {y1: 0, y2: 1 + k * eStar * eStar, stroke: "#6B6357", strokeDasharray: "4,3"}),
      Plot.ruleX([eMshown], {y1: 0, y2: 1 + k * (1 - theta) * eMshown * eMshown,
                             stroke: "#6B6357", strokeDasharray: "4,3"}),

      // Equilibrium dots: each on the curve the agent actually faces
      Plot.dot([{e: eStar, C: 1 + k * eStar * eStar}],
        {x: "e", y: "C", r: 5, fill: "#6B1F26", stroke: "white", strokeWidth: 2}),
      Plot.dot([{e: eMshown, C: 1 + k * (1 - theta) * eMshown * eMshown}],
        {x: "e", y: "C", r: 5, fill: "#1C1916", stroke: "white", strokeWidth: 2}),

      // Curve labels
      Plot.text([{x: emax * 0.78, y: 1 + k * (emax * 0.78) * (emax * 0.78), label: "Bez osiguranja"}],
        {x: "x", y: "y", text: "label", fill: "#6B1F26", fontSize: 12, fontWeight: 700,
         dy: -10, textAnchor: "end"}),
      Plot.text([{x: emax * 0.88, y: 1 + k * (1 - theta) * (emax * 0.88) * (emax * 0.88),
                  label: "S osiguranjem (moralni hazard)"}],
        {x: "x", y: "y", text: "label", fill: "#1C1916", fontSize: 12, fontWeight: 700,
         dy: -10, textAnchor: "end"}),

      // x-axis labels for e* and eM
      Plot.text([{x: eStar, y: 0.4, label: `e* = ${eStar.toFixed(2)}`}],
        {x: "x", y: "y", text: "label", textAnchor: "middle", fontSize: 11, fill: "#6B1F26"}),
      Plot.text([{x: eMshown, y: 0.4, label: `e_M = ${eM.toFixed(2)}`}],
        {x: "x", y: "y", text: "label", textAnchor: "middle", fontSize: 11, fill: "#1C1916"}),

      // Top readouts
      Plot.text([{x: 0.2, y: Cmax * 0.97,
        label: `Porast rizika: e_M − e* = ${(eM - eStar).toFixed(2)} (+${(((eM - eStar) / eStar) * 100).toFixed(0)} %)`}],
        {x: "x", y: "y", text: "label", textAnchor: "start",
         fontSize: 14, fill: "#1C1916", fontWeight: 700}),
      Plot.text([{x: 0.2, y: Cmax * 0.91,
        label: `Neefikasnost (gubitak blagostanja) = ${dwl.toFixed(2)}`}],
        {x: "x", y: "y", text: "label", textAnchor: "start",
         fontSize: 13, fill: "#6B1F26", fontWeight: 600})
    ]
  });
}









Slika 5: Moralni hazard: osiguranje smanjuje percipiranu krivulju troška, pa agent bira višu razinu rizičnog ponašanja e_M umjesto optimalne e*.




Što isprobati. (1) Povećavajte pokriće osiguranja (θ) prema 0,9 i pratite kako krivulja S osiguranjem postaje sve plića, pa agent klizi s optimalne razine e* na sve viši e_M, a postotni porast rizika i neefikasnost rastu. (2) Vratite (θ) na nulu i vidjet ćete da se dvije krivulje poklope, pa e_M pada na e* i moralni hazard nestaje jer agent ponovno snosi puni trošak. (3) Uz osiguranje smanjite konveksnost troška (k) i primijetite protuintuitivan ishod, naime da blaži rast troška znači slabiju prirodnu kočnicu rizika, pa iste razine pokrića vode k razmjerno većem skoku e_M nego kad je trošak strmo konveksan.
Asimetrične informacije posebno su važne u zdravstvu, financijama, obrazovanju, osiguranju i tržištu rada. Pacijent obično zna manje od liječnika o dijagnozi, terapiji i kvaliteti liječenja. Štediša zna manje od financijske institucije o složenim financijskim proizvodima. Roditelj ne može uvijek lako procijeniti kvalitetu škole. Poslodavac ne zna uvijek stvarnu produktivnost radnika prije zapošljavanja.
Prije nego što se umiješa država, na te probleme reagira i samo tržište. Bolje informirana strana ima poticaj svoje skriveno svojstvo učiniti vidljivim kroz signaliziranje, odnosno kroz skupu i teško krivotvorivu radnju koju si može priuštiti samo onaj tko doista posjeduje kvalitetu, poput diplome koja poslodavcu signalizira sposobnost ili jamstva kojim prodavač jamči za stanje automobila (Spence 1973). Slabije informirana strana zauzvrat pribjegava probiru (screening), nudeći niz ugovora osmišljenih tako da se sugovornici sami razvrstaju prema svojem skrivenom tipu, kao kad osiguravatelj ponudi izbor između police s visokim sudjelovanjem u šteti i skuplje police s punim pokrićem, pa se rizičniji i manje rizični osiguranici sami otkriju izborom (Rothschild i Stiglitz 1976). Tek kada su takvi tržišni mehanizmi preskupi ili kada se uspostavi ravnoteža u kojoj se tipovi ne mogu razdvojiti, postaje jasno gdje državna intervencija doista dodaje vrijednost, a ne samo dvostruko pokriva ono što bi tržište riješilo samo.

Spence, Michael. 1973. „Job Market Signaling“. Quarterly Journal of Economics 87 (3): 355–74. https://doi.org/10.2307/1882010.

Rothschild, Michael, i Joseph E. Stiglitz. 1976. „Equilibrium in Competitive Insurance Markets: An Essay on the Economics of Imperfect Information“. Quarterly Journal of Economics 90 (4): 629–49. https://doi.org/10.2307/1885326.
Država može smanjiti informacijske probleme na više načina. Može propisati obvezno objavljivanje informacija, primjerice deklaracije na hrani, energetske certifikate, financijske prospekte, informacije o kamatnim stopama ili usporedive podatke o kvaliteti javnih usluga. Može uvesti licenciranje i standarde za liječnike, odvjetnike, revizore, nastavnike ili financijske institucije. Može uspostaviti nadzorne agencije, javne registre, sustave certifikacije i mehanizme zaštite potrošača.
No informacijske mjere nisu uvijek dovoljne. Informacije moraju biti razumljive, dostupne i vjerodostojne. Ako potrošač dobije dokument od pedeset stranica, formalno je informiran, ali stvarno možda nije sposoban donijeti bolju odluku. Zato se u suvremenim javnim politikama sve više naglašava jednostavnost informacija, standardizirani prikazi, jasna upozorenja i bihevioralni uvidi u način na koji ljudi donose odluke.

Tržišna moć i monopol
Četvrti oblik tržišnog neuspjeha je tržišna moć, posebno monopol. U idealnom konkurentskom tržištu nijedno poduzeće ne može samo određivati cijenu. Poduzeća se natječu, potrošači biraju, a cijene odražavaju troškove i preferencije. Međutim, kada jedno poduzeće ili mali broj poduzeća ima značajnu tržišnu moć, taj se mehanizam narušava.
Monopol nastaje kada na tržištu postoji samo jedan ponuđač određenog dobra ili usluge. Monopolist može ograničiti količinu proizvodnje i naplatiti cijenu višu od konkurentske. Potrošači tada plaćaju više, kupuju manje, a dio potencijalne društvene koristi nestaje. U ekonomskoj analizi taj gubitak naziva se mrtvi teret monopola. Problem monopola nije samo u tome da monopolist ostvaruje visoku dobit, nego u tome da društvo dobiva manju količinu dobra po višoj cijeni nego što bi dobilo u uvjetima konkurencije.
Tržišna moć može nastati iz više razloga. Može biti posljedica vlasništva nad ključnim resursom, patenata, visokih početnih ulaganja, regulatornih prepreka ulasku, mrežnih učinaka ili strateškog ponašanja poduzeća. U nekim digitalnim tržištima tržišna moć nastaje jer vrijednost usluge raste s brojem korisnika. Što više ljudi koristi neku platformu, to ona postaje korisnija novim korisnicima, pa konkurenti sve teže ulaze na tržište.

Definicija 5 Prirodni monopol nastaje kada su fiksni troškovi infrastrukture toliko visoki da prosječni trošak neprekidno pada s količinom, pa jedan ponuđač može sve kupce poslužiti po nižem trošku nego dva ili više. Konkurencija na takvom tržištu nije stabilna jer naposljetku pobjeđuje jedan ponuđač, pa regulacija postaje zamjena za tržišnu disciplinu.

Poseban slučaj je prirodni monopol. Prirodni monopol nastaje kada su fiksni troškovi vrlo visoki, a prosječni troškovi padaju kako se povećava količina proizvodnje. U takvim okolnostima jedan veliki ponuđač može proizvoditi po nižem trošku nego više manjih ponuđača. Primjeri su vodoopskrba, elektroenergetske mreže, plinovodi, željeznička infrastruktura i određene komunalne usluge.
Graf koji slijedi prikazuje kako tržišna moć podiže cijenu i smanjuje proizvedenu količinu u odnosu na konkurenciju. Monopolist određuje količinu na razini gdje se marginalni prihod (MR) izjednačava s marginalnim troškom (MC), a zatim postavlja cijenu prema krivulji potražnje D. Rezultat je niža količina QM i viša cijena PM u odnosu na konkurentsku ravnotežu (QC, PC), u kojoj bi D sjekao MC, a osjenčani trokut između QM i QC predstavlja gubitak blagostanja (deadweight loss) zbog tržišne moći. Graf je interaktivan, pa klizači mijenjaju elastičnost potražnje i nagib marginalnog troška.


Prikaži kod
viewof mon_controls = Inputs.form({
  eps_d_mon: Inputs.range([0.5, 3.0], {value: 1.2, step: 0.05, label: "Elastičnost potražnje |εD|:"}),
  eps_s_mon: Inputs.range([0.4, 3.0], {value: 1.2, step: 0.05, label: "Elastičnost MC (εS):"})
})









Prikaži kod
eps_d_mon = mon_controls.eps_d_mon









Prikaži kod
eps_s_mon = mon_controls.eps_s_mon









Prikaži kod
{
  // Anchor competitive equilibrium at (Qc, Pc) = (60, 50)
  const Qc   = 60;
  const Pc   = 50;
  const Qmax = 110;
  const Pmax = 120;

  // Slopes from elasticities at competitive equilibrium
  const b = Pc / (Qc * eps_d_mon);   // demand slope
  const d = Pc / (Qc * eps_s_mon);   // MC slope

  // Demand: P = a - b*Q,  at (Qc, Pc): a = Pc + b*Qc
  const a = Pc + b * Qc;
  // MC: P = c + d*Q,  at (Qc, Pc): c = Pc - d*Qc
  const c = Pc - d * Qc;

  // Monopoly: MR = MC  =&gt;  a - 2b*Qm = c + d*Qm  =&gt;  Qm = (a - c)/(2b + d)
  const Qm = (a - c) / (2 * b + d);
  const Pm = a - b * Qm;               // monopoly price (on demand curve)
  const MC_at_Qm = c + d * Qm;         // marginal cost at Qm

  const Qs = d3.range(0, Qmax + 1);
  const demand = Qs.map(q =&gt; ({Q: q, P: a - b * q}))
                   .filter(p =&gt; p.P &gt;= 0 && p.P &lt;= Pmax);
  const mr     = Qs.map(q =&gt; ({Q: q, P: a - 2 * b * q}))
                   .filter(p =&gt; p.P &gt;= -Pmax && p.P &lt;= Pmax);
  const mc     = Qs.map(q =&gt; ({Q: q, P: c + d * q}))
                   .filter(p =&gt; p.P &gt;= 0 && p.P &lt;= Pmax);

  // DWL triangle: vertices (Qm, Pm), (Qm, MC_at_Qm), (Qc, Pc)
  const dwlTri = [
    {Q: Qm, P: Pm},
    {Q: Qm, P: MC_at_Qm},
    {Q: Qc, P: Pc}
  ];

  const dwl = 0.5 * Math.abs(Pm - MC_at_Qm) * Math.abs(Qc - Qm);
  const markup = ((Pm - Pc) / Pc) * 100;

  return Plot.plot({
    width: 760,
    height: 500,
    marginLeft: 65,
    marginBottom: 55,
    style: {fontSize: "12px", fontFamily: "Public Sans, system-ui, sans-serif", color: "#3A332D"},
    x: {label: "Količina (Q) →", domain: [0, Qmax], grid: false},
    y: {label: "↑ Cijena (P)",    domain: [0, Pmax], grid: true},
    marks: [
      Plot.ruleY([0], {stroke: "#C9C3B8"}),

      // DWL triangle (shaded)
      Plot.line([...dwlTri, dwlTri[0]],
        {x: "Q", y: "P", stroke: "#6B1F26", strokeWidth: 1,
         fill: "#D8B5B3", fillOpacity: 0.65, curve: "linear"}),

      // Curves
      Plot.line(demand, {x: "Q", y: "P", stroke: "#2D5A8E", strokeWidth: 2.5}),
      Plot.line(mr,     {x: "Q", y: "P", stroke: "#3A332D", strokeWidth: 2, strokeDasharray: "5,4"}),
      Plot.line(mc,     {x: "Q", y: "P", stroke: "#4A6B5C", strokeWidth: 2}),

      // Dashed guides for prices and quantities
      Plot.ruleY([Pm], {stroke: "#6B6357", strokeDasharray: "4,3"}),
      Plot.ruleY([Pc], {stroke: "#6B6357", strokeDasharray: "4,3"}),
      Plot.ruleX([Qm], {y1: 0, y2: Pm, stroke: "#6B6357", strokeDasharray: "4,3"}),
      Plot.ruleX([Qc], {y1: 0, y2: Pc, stroke: "#6B6357", strokeDasharray: "4,3"}),

      // Equilibrium dots
      Plot.dot([{Q: Qm, P: Pm}],
        {x: "Q", y: "P", r: 5, fill: "#6B1F26", stroke: "white", strokeWidth: 2}),
      Plot.dot([{Q: Qc, P: Pc}],
        {x: "Q", y: "P", r: 5, fill: "#4A6B5C", stroke: "white", strokeWidth: 2}),
      Plot.dot([{Q: Qm, P: MC_at_Qm}],
        {x: "Q", y: "P", r: 4, fill: "#1C1916", stroke: "white", strokeWidth: 1.5}),

      // Curve labels
      Plot.text([{x: Qmax * 0.82, y: a - b * Qmax * 0.82, label: `D (|εD|=${eps_d_mon.toFixed(2)})`}],
        {x: "x", y: "y", text: "label", fill: "#2D5A8E", fontSize: 12, fontWeight: 600, dy: -8}),
      Plot.text([{x: Qmax * 0.42, y: a - 2 * b * Qmax * 0.42, label: "MR"}],
        {x: "x", y: "y", text: "label", fill: "#3A332D", fontSize: 12, fontWeight: 700, dy: -8}),
      Plot.text([{x: Qmax * 0.82, y: c + d * Qmax * 0.82, label: `MC (εS=${eps_s_mon.toFixed(2)})`}],
        {x: "x", y: "y", text: "label", fill: "#4A6B5C", fontSize: 12, fontWeight: 600, dy: -8}),

      // Price & quantity labels
      Plot.text([{x: 1, y: Pm, label: `P_M = ${Pm.toFixed(1)}`}],
        {x: "x", y: "y", text: "label", textAnchor: "start", dy: -7, fontSize: 11, fill: "#6B1F26"}),
      Plot.text([{x: 1, y: Pc, label: `P_C = ${Pc.toFixed(1)}`}],
        {x: "x", y: "y", text: "label", textAnchor: "start", dy: 12, fontSize: 11, fill: "#4A6B5C"}),
      Plot.text([{x: Qm, y: 2, label: `Q_M = ${Qm.toFixed(1)}`}],
        {x: "x", y: "y", text: "label", textAnchor: "middle", fontSize: 11, fill: "#6B1F26"}),
      Plot.text([{x: Qc, y: 2, label: `Q_C = ${Qc.toFixed(1)}`}],
        {x: "x", y: "y", text: "label", textAnchor: "middle", fontSize: 11, fill: "#4A6B5C"}),

      // Top readouts
      Plot.text([{x: 2, y: Pmax * 0.97,
        label: `Gubitak blagostanja (DWL) = ${dwl.toFixed(1)}`}],
        {x: "x", y: "y", text: "label", textAnchor: "start",
         fontSize: 14, fill: "#6B1F26", fontWeight: 700}),
      Plot.text([{x: 2, y: Pmax * 0.91,
        label: `Monopolska marža: ${markup.toFixed(0)} %`}],
        {x: "x", y: "y", text: "label", textAnchor: "start",
         fontSize: 13, fill: "#1C1916", fontWeight: 600})
    ]
  });
}









Slika 6: Monopol i gubitak blagostanja: monopolist ograničava količinu na Q_M i podiže cijenu na P_M iznad konkurentske razine (Q_C, P_C), čime nastaje osjenčani trokut mrtvog tereta.




Što isprobati. (1) Smanjite elastičnost potražnje |εD| prema 0,5 i pratite kako monopolist širi razmak između Q_M i konkurentske količine Q_C, pa monopolska marža i osjenčani trokut mrtvog tereta rastu. (2) Povećajte |εD| prema 3,0 i vidjet ćete kako se Q_M približava Q_C, a cijena P_M pada prema konkurentskoj P_C jer kupci koji lako odustaju oduzimaju monopolistu prostor za podizanje cijene. (3) Uz elastičnu potražnju spustite elastičnost MC (εS) prema 0,4 i primijetite protuintuitivan ishod, naime da strmiji marginalni trošak sam po sebi sužava jaz količina, pa gubitak blagostanja od monopola ovisi ne samo o tržišnoj moći nego i o tome koliko se brzo penju troškovi proizvodnje.
Država može odgovoriti na tržišnu moć na nekoliko načina. Prvi je politika zaštite tržišnog natjecanja. Ona uključuje zabranu kartela, nadzor spajanja poduzeća, sprječavanje zloupotrebe dominantnog položaja i uklanjanje neopravdanih prepreka ulasku na tržište. Cilj nije kažnjavati velika poduzeća zato što su velika, nego spriječiti ponašanja koja ograničavaju konkurenciju i štete potrošačima.
Drugi odgovor je regulacija prirodnih monopola. Ako nije učinkovito imati više ponuđača, država može regulirati cijene, kvalitetu usluge, investicije i pristup infrastrukturi.
Sama regulacija cijena, međutim, nije bez vlastitih izobličenja. Kada regulator dopušta poduzeću prinos vezan uz vrijednost njegova kapitala, poduzeće dobiva poticaj predimenzionirati ulaganja i napuhati kapitalnu osnovicu kako bi povećalo dopuštenu dobit, čak i ondje gdje to nije najjeftiniji način pružanja usluge (Averch i Johnson 1962). Zbog tog su učinka razvijene regulacije koje cijenu vežu uz unaprijed zadanu putanju umjesto uz trošak, pa poduzeću prepuštaju uštede koje samo pronađe i time mu vraćaju poticaj na učinkovitost, doduše uz slabije jamstvo kvalitete. Pouka je da reguliranje monopola nije čist popravak nego problem dizajna instrumenta s vlastitim kompromisima, jednako kao i intervencije kod ostalih oblika tržišnog neuspjeha.

Averch, Harvey, i Leland L. Johnson. 1962. „Behavior of the Firm under Regulatory Constraint“. American Economic Review 52 (5): 1052–69.
Treći odgovor je javno vlasništvo. Država može odlučiti da određeni prirodni monopol bude u javnom vlasništvu, osobito ako se radi o strateški važnoj infrastrukturi. Međutim, javno vlasništvo samo po sebi ne jamči učinkovitost. Javna poduzeća mogu imati probleme političkog utjecaja, slabih poticaja i neučinkovitog upravljanja.
Tržišna moć pokazuje da konkurencija nije uvijek prirodno i trajno stanje tržišta. Ponekad je država potrebna upravo zato da bi zaštitila konkurenciju. U tom smislu država nije nužno protiv tržišta, nego može biti čuvar uvjeta pod kojima tržište može funkcionirati.

Fiskalni multiplikator
Tvrdnja da država potrošnjom i porezima pomiče ukupnu potražnju ostaje neodređena dok ne znamo koliko snažno to čini. Koliko proizvodnje pokrene jedan euro javne potrošnje pitanje je na koje odgovara fiskalni multiplikator.
Fiskalni multiplikator pokazuje za koliko se promijeni proizvodnja kada se promijeni neka fiskalna varijabla. U jednostavnom keynesijanskom okviru početni fiskalni impuls ne djeluje samo jednom, nego se širi kroz gospodarstvo. Dodatna potrošnja postaje nečiji dohodak, dio tog dohotka ponovno se troši, pa ukupni učinak na BDP može biti veći od početnog impulsa.

Definicija 1 Fiskalni multiplikator je omjer ukupne promjene BDP-a i početne promjene fiskalne varijable (potrošnje ili poreza) koja tu promjenu uzrokuje. Ako povećanje državne potrošnje za 1 mlrd. eura podiže BDP za 1,5 mlrd. eura, multiplikator je 1,5. Ovisi o graničnoj sklonosti potrošnji, otvorenosti gospodarstva i stanju monetarne politike.

U lijevom panelu prikazano je povećanje državne potrošnje. Budući da je državna potrošnja sastavnica agregatne potražnje, njezin rast izravno pomiče krivulju planiranih izdataka prema gore. Nova ravnoteža nastaje na višoj razini proizvodnje, pa je multiplikator državne potrošnje pozitivan.
U desnom panelu prikazano je povećanje poreza. Viši porezi smanjuju raspoloživi dohodak kućanstava, a time i osobnu potrošnju. Zato se agregatna potražnja pomiče prema dolje, a ravnotežna proizvodnja pada, pa je porezni multiplikator negativan. Graf je interaktivan, pa klizači mijenjaju porast državne potrošnje, porast poreza i graničnu sklonost potrošnji.


Prikaži kod
viewof fm_controls = Inputs.form({
  c:  Inputs.range([0.50, 0.85], {value: 0.70, step: 0.01, label: "Granična sklonost potrošnji (c):"}),
  dG: Inputs.range([0,    60],   {value: 30,   step: 1,    label: "Porast državne potrošnje (ΔG):"}),
  dT: Inputs.range([0,    60],   {value: 30,   step: 1,    label: "Porast poreza (ΔT):"})
})









Prikaži kod
fm_c = fm_controls.c









Prikaži kod
fm_dG = fm_controls.dG









Prikaži kod
fm_dT = fm_controls.dT









Prikaži kod
{
  const A0 = 100;             // autonomous expenditure (fixed)
  const c  = fm_c;
  const dG = fm_dG;
  const dT = fm_dT;
  const Ymax = 1400;

  // Equilibria: AE = A0 + c·Y intersects 45° line at Y = A0/(1-c)
  const Y0  = A0 / (1 - c);
  const Y1G = (A0 + dG) / (1 - c);
  const Y1T = (A0 - c * dT) / (1 - c);

  const multG = 1 / (1 - c);
  const multT = -c / (1 - c);

  const POLICY_G = "Povećanje državne potrošnje";
  const POLICY_T = "Povećanje poreza";

  const grid = d3.range(0, Ymax + 10, 10);

  // 45° line — drawn in both facets
  const line45 = grid.flatMap(y =&gt; [
    {Y: y, AE: y, policy: POLICY_G},
    {Y: y, AE: y, policy: POLICY_T}
  ]);

  // Original AE = A0 + c·Y — drawn in both facets
  const ae0Data = grid.flatMap(y =&gt; {
    const ae = A0 + c * y;
    if (ae &gt; Ymax) return [];
    return [
      {Y: y, AE: ae, policy: POLICY_G},
      {Y: y, AE: ae, policy: POLICY_T}
    ];
  });

  // Shifted AE curves — one per facet
  const ae1G = grid.map(y =&gt; ({Y: y, AE: A0 + dG + c * y, policy: POLICY_G}))
                   .filter(p =&gt; p.AE &lt;= Ymax);
  const ae1T = grid.map(y =&gt; ({Y: y, AE: A0 - c * dT + c * y, policy: POLICY_T}))
                   .filter(p =&gt; p.AE &lt;= Ymax && p.AE &gt;= 0);

  // Equilibrium dots
  const dots = [
    {Y: Y0,  AE: Y0,  policy: POLICY_G},
    {Y: Y1G, AE: Y1G, policy: POLICY_G},
    {Y: Y0,  AE: Y0,  policy: POLICY_T},
    {Y: Y1T, AE: Y1T, policy: POLICY_T}
  ];

  // Vertical dashed guides — one datum per rule, routed via fx
  const guideG = [
    {Yx: Y0,  yTop: Y0,  policy: POLICY_G},
    {Yx: Y1G, yTop: Y1G, policy: POLICY_G}
  ];
  const guideT = [
    {Yx: Y0,  yTop: Y0,  policy: POLICY_T},
    {Yx: Y1T, yTop: Y1T, policy: POLICY_T}
  ];

  // Bottom Y0 / Y1 readouts
  const bottomLabels = [
    {Y: Y0,  AE: 14, label: `Y₀ = ${Y0.toFixed(0)}`,  policy: POLICY_G},
    {Y: Y1G, AE: 14, label: `Y₁ = ${Y1G.toFixed(0)}`, policy: POLICY_G},
    {Y: Y0,  AE: 14, label: `Y₀ = ${Y0.toFixed(0)}`,  policy: POLICY_T},
    {Y: Y1T, AE: 14, label: `Y₁ = ${Y1T.toFixed(0)}`, policy: POLICY_T}
  ];

  // 45° text marker (top-right of each panel)
  const fortyfiveLabel = [
    {Y: Ymax * 0.92, AE: Ymax * 0.92, label: "45°", policy: POLICY_G},
    {Y: Ymax * 0.92, AE: Ymax * 0.92, label: "45°", policy: POLICY_T}
  ];

  // Multiplier readout at top
  const topLabels = [
